// 1. Get the raw output (Could be a String OR an Object)
let raw = $input.item.json.output;

// 2. Normalize: If it's a string (Scenario A), parse it into an object first
if (typeof raw === 'string') {
    try {
        // Clean markdown wrapper if present
        raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
        raw = JSON.parse(raw);
    } catch (e) {
        // If parsing fails, treat it as a text object
        raw = { response_to_user: raw };
    }
}

// 3. Extract the initial text (Scenario B)
// If raw was null/undefined, default to empty object
raw = raw || {};
let finalParams = raw.response_to_user || raw.text || raw.response || "";

// 4. Double-Check: Is the extracted text actually HIDDEN JSON? (Scenario C - The "Dirty" case)
if (typeof finalParams === 'string' && (finalParams.trim().startsWith('{') || finalParams.trim().startsWith('```'))) {
    try {
        const cleanRaw = finalParams.replace(/```json/g, '').replace(/```/g, '').trim();
        const parsedDeep = JSON.parse(cleanRaw);
        finalParams = parsedDeep.response_to_user || parsedDeep.text || finalParams;
    } catch (e) {
        // If deep parse fails, try regex to grab the value manually
        const match = finalParams.match(/"response_to_user"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        if (match) {
            finalParams = match[1];
        }
    }
}

// 5. Final fallback: If empty, verify if we missed the text in a weird field
if (!finalParams && typeof raw === 'string') {
    finalParams = raw; 
}

return {
  json: {
    output: {
      response_to_user: finalParams
    }
  }
};

